ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/demographics#>
PREFIX p: <http://ambrosia.example.org/demographics/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?region_name WHERE {
  ?immigrants a :Immigrants .
  ?regions a :Regions .
  ?immigrants p:hasRegions ?regions .
  ?regions p:region_name ?region_name .
  ?immigrants p:gender ?gender_f .
  FILTER(?gender_f = "F")
} }
  full: { SELECT ?country_name ?region_of_origin WHERE {
  ?immigrants a :Immigrants .
  ?countries a :Countries .
  ?immigrants p:hasCountries ?countries .
  ?regions a :Regions .
  ?immigrants p:hasRegions ?regions .
  ?countries p:country_name ?country_name .
  ?immigrants p:region_of_origin ?region_of_origin .
  ?immigrants p:gender ?gender_f .
  FILTER(?gender_f = "F")
} }
  component_2: { SELECT ?country_name WHERE {
  ?immigrants a :Immigrants .
  ?countries a :Countries .
  ?immigrants p:hasCountries ?countries .
  ?countries p:country_name ?country_name .
  ?immigrants p:gender ?gender_f .
  FILTER(?gender_f = "F")
} }
}

PREFIX : <http://ambrosia.example.org/demographics#>
PREFIX p: <http://ambrosia.example.org/demographics/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?region_name WHERE {
  ?immigrants a :Immigrants .
  ?regions a :Regions .
  ?immigrants p:hasRegions ?regions .
  ?regions p:region_name ?region_name .
  ?immigrants p:age ?age_o .
}
ORDER BY ASC(?age_o)
LIMIT 1 }
  full: { SELECT ?country_name ?region_name WHERE {
  ?immigrants a :Immigrants .
  ?countries a :Countries .
